// Drop in a <script> block; converts data points into the polyline/path strings above.
function sparkPath(values, w = 100, h = 32, pad = 2) {
  const min = Math.min(...values), max = Math.max(...values);
  const range = max - min || 1;
  const step = w / (values.length - 1);
  const pts = values.map((v, i) => [i * step, h - pad - ((v - min) / range) * (h - pad * 2)]);
  const poly = pts.map(([x, y]) => `${x},${y}`).join(' ');
  const area = `M${poly.replace(/ /g, ' L')} L${w},${h} L0,${h} Z`;
  return { poly, area };
}
